`timescale 1ns / 1ps

// tb_fft64_radix4_sdf.v -- Self-checking Verilog testbench for fft64_radix4_sdf.
// Generated by VeriFlow-CC.
//
// Tests all 4 golden model test vectors:
//   1. impulse_idx0    - Impulse at index 0 (all bins equal magnitude)
//   2. constant_dc     - DC signal (bin 0 only)
//   3. single_freq_k1  - Single frequency bin k=1
//   4. random_complex  - Pseudo-random complex input
//
// Compares RTL output against pre-computed expected values from golden_model.py.
// Uses toleranced comparison (TOL_LSB) to account for Q1.15 quantization.
// Reports PASS/FAIL per sample and overall.

module tb_fft64_radix4_sdf;

    // =========================================================================
    // Parameters
    // =========================================================================
    parameter N = 64;                  // FFT size
    parameter DATA_W = 16;             // Q1.15 data width
    parameter PIPELINE_LATENCY = 67;   // cycles from first in_valid to first out_valid
    parameter TOL_LSB = 4;             // tolerance in LSBs for Q1.15 comparison
    parameter CLK_PERIOD_NS = 10;      // 100 MHz full period
    parameter HALF_PERIOD_NS = 5;      // half period

    // =========================================================================
    // Port declarations matching DUT
    // =========================================================================
    reg         clk;
