    // Cycle counter and fail counter
    integer cycle_count = 0;
    integer fail_count  = 0;
    integer test_pass_count = 0;

    // =========================================================================
    // DUT instantiation
    // =========================================================================
    fft64_radix4_sdf uut (
        .clk        (clk),
        .rst_n      (rst_n),
