        .in_data_im (in_data_im),
        .out_valid  (out_valid),
        .out_data_re(out_data_re),
        .out_data_im(out_data_im),
        .out_index  (out_index)
    );

    // =========================================================================
    // Clock generation (half-period from target frequency)
    // =========================================================================
    initial clk = 0;
    always #HALF_PERIOD_NS clk = ~clk;

    // Cycle counter -- increment every posedge
    always @(posedge clk) cycle_count = cycle_count + 1;

    // =========================================================================
    // VCD capture
    // =========================================================================
    initial begin
        $dumpfile("tb_fft64_radix4_sdf.vcd");
        $dumpvars(0, tb_fft64_radix4_sdf);
    end

    // =========================================================================
    // TESTBENCH TIMING METHODOLOGY
    // =========================================================================
    //
    // Rule 1: NBA FOR DUT INPUTS (MANDATORY)
    //   All DUT input assignments in initial blocks MUST use non-blocking
    //   assignment (<=). This prevents race conditions between the testbench
    //   and the DUT's sequential always blocks at the same posedge.
    //
    // Rule 2: RESET SEQUENCE TIMING (async active-low)
    //   rst_n = 1'b0;                     // blocking OK for reset only
    //   <zero all data inputs with <=>
    //   @(posedge clk); @(posedge clk);   // hold reset 2+ cycles
    //   rst_n = 1'b1;                     // blocking OK for reset only
    //   @(negedge clk);                   // wait for NBA to settle
    //
    // Rule 3: STREAMING FFT -- no multi-block, no is_last, no backpressure.
    //   Drive 64 samples with in_valid=1, deassert, wait for pipeline latency,
    //   then capture 64 outputs.
    //
    // Rule 4: OUTPUT SAMPLING -- posedge vs negedge
    //   PULSE signals (out_valid): detect at posedge.
    //   REGISTERED DATA (out_data_re/im, out_index): sample at negedge AFTER
    //   the posedge where out_valid was detected.
    //
    // Rule 5: TIMING CONTRACT
    //   Pipeline latency = 67 cycles from first in_valid to first out_valid.
    //   Registered outputs: stable between posedge and negedge.
    //
    // =========================================================================

    // =========================================================================
    // MACROS: Race-free sampling helpers
    // =========================================================================
    `define SAMPLE_REGISTERED_OUTPUT(sig, expected, test_name, idx) \
        @(negedge clk); \
        if (sig !== expected) begin \
            if ((sig > expected) ? ((sig - expected) > TOL_LSB) : ((expected - sig) > TOL_LSB)) begin \
                $display("[FAIL] test=%s sample[%0d] signal=%s kind=registered width=%0db expected=0x%0h actual=0x%0h xor=0x%0h phase=negedge", \
                         test_name, idx, `"sig`", $bits(sig), expected, sig, (expected ^ sig)); \
                fail_count = fail_count + 1; \
            end \
        end else \
            $display("[PASS] test=%s sample[%0d] signal=%s kind=registered width=%0db actual=0x%0h phase=negedge", \
                     test_name, idx, `"sig`", $bits(sig), sig);

    `define CHECK_TOLERANCED(actual, expected, test_name, idx, comp_name) \
        if (actual !== expected) begin \
            if ((actual > expected) ? ((actual - expected) > TOL_LSB) : ((expected - actual) > TOL_LSB)) begin \
                $display("[FAIL] test=%s sample[%0d] signal=%s expected=0x%0h actual=0x%0h xor=0x%0h", \
                         test_name, idx, comp_name, expected, actual, (expected ^ actual)); \
                fail_count = fail_count + 1; \
            end \
        end

    // =========================================================================
    // RESET TASK: Must be called at start of EVERY independent test
    // =========================================================================
    task automatic apply_reset;
        begin
            rst_n = 1'b0;                    // blocking OK for reset only
            in_valid   <= 1'b0;
            in_data_re <= 16'h0000;
            in_data_im <= 16'h0000;
            @(posedge clk); @(posedge clk); @(posedge clk);
            rst_n = 1'b1;                    // blocking OK for reset only
            @(negedge clk);                  // wait for NBA to settle after rst_n deassert
            $display("[TRACE] cycle=%0d rst_n released", cycle_count);
        end
    endtask

    // =========================================================================
    // DRIVE_FFT_INPUTS task: Drive 64 samples with in_valid=1
    // =========================================================================
    task automatic drive_fft_inputs;
        input [15:0] re_mem [0:63];
        input [15:0] im_mem [0:63];
        integer i;
        begin
            in_valid <= 1'b0;
            in_data_re <= 16'h0000;
            in_data_im <= 16'h0000;
            @(posedge clk);

            for (i = 0; i < 64; i = i + 1) begin
                in_valid   <= 1'b1;
                in_data_re <= re_mem[i];
                in_data_im <= im_mem[i];
                @(posedge clk);
            end

            in_valid   <= 1'b0;
            in_data_re <= 16'h0000;
            in_data_im <= 16'h0000;
        end
    endtask

    // =========================================================================
    // CAPTURE_AND_CHECK task: Wait for pipeline, capture 64 outputs, compare
    // =========================================================================
    task automatic capture_and_check;
        input [15:0] exp_re [0:63];
        input [15:0] exp_im [0:63];
        input [255:0] test_name_str;
        integer i;
        integer captured;
        integer max_err_re;
        integer max_err_im;
        integer err_re;
        integer err_im;
        integer total_err_sq;
        integer sig_sq;
        integer sample_pass_count;
        reg [15:0] act_re;
        reg [15:0] act_im;
        reg [5:0]  act_idx;
        begin
            // Wait for pipeline latency
            for (i = 0; i < PIPELINE_LATENCY; i = i + 1)
                @(posedge clk);

            // Capture 64 outputs
            captured = 0;
            max_err_re = 0;
            max_err_im = 0;
            total_err_sq = 0;
            sig_sq = 0;
            sample_pass_count = 0;

            for (i = 0; i < 64 + 20; i = i + 1) begin
                @(posedge clk);
                if (out_valid === 1'b1) begin
                    @(negedge clk);  // wait for NBA to settle on registered outputs
                    act_re = out_data_re;
                    act_im = out_data_im;
                    act_idx = out_index;

                    // Toleranced comparison
                    err_re = (act_re > exp_re[captured]) ? (act_re - exp_re[captured]) : (exp_re[captured] - act_re);
                    err_im = (act_im > exp_im[captured]) ? (act_im - exp_im[captured]) : (exp_im[captured] - act_im);

                    if ((err_re > TOL_LSB) || (err_im > TOL_LSB)) begin
                        $display("[FAIL] test=%0s sample[%0d] idx=%0d expected_re=0x%04h actual_re=0x%04h expected_im=0x%04h actual_im=0x%04h",
                                 test_name_str, captured, act_idx,
                                 exp_re[captured], act_re,
                                 exp_im[captured], act_im);
                        fail_count = fail_count + 1;
                    end else begin
                        sample_pass_count = sample_pass_count + 1;
                    end

                    captured = captured + 1;
                    if (captured >= 64)
                        break;
                end
            end

            if (captured < 64) begin
                $display("[FAIL] test=%0s Only captured %0d/64 output samples",
                         test_name_str, captured);
                fail_count = fail_count + 1;
            end else if (sample_pass_count == 64) begin
                $display("[PASS] test=%0s All 64 samples matched (tolerance=%0d LSB)", test_name_str, TOL_LSB);
                test_pass_count = test_pass_count + 1;
            end else begin
                $display("[WARN] test=%0s %0d/64 samples matched, %0d outside tolerance",
                         test_name_str, sample_pass_count, 64 - sample_pass_count);
            end
        end
    endtask

